package com.example.yourapp; // Replace with your actual package name

import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.widget.ImageView;
import android.widget.TextView;
import androidx.appcompat.app.AppCompatActivity;
import java.util.ArrayList;

public class ShareReceiverActivity extends AppCompatActivity {

    private TextView statusTextView;
    private ImageView sharedImageView;
    private TextView sharedTextView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_share_receiver);

        statusTextView = findViewById(R.id.statusTextView);
        sharedImageView = findViewById(R.id.sharedImageView);
        sharedTextView = findViewById(R.id.sharedTextView);

        handleIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent); // Update the activity's intent
        handleIntent(intent);
    }

    private void handleIntent(Intent intent) {
        String action = intent.getAction();
        String type = intent.getType();

        // Reset UI elements
        statusTextView.setText("Waiting for shared content...");
        sharedImageView.setVisibility(ImageView.GONE);
        sharedImageView.setImageDrawable(null); // Clear previous image
        sharedTextView.setVisibility(TextView.GONE);
        sharedTextView.setText("");

        if (Intent.ACTION_SEND.equals(action) && type != null) {
            if (type.startsWith("image/")) {
                handleSendImage(intent);
            } else if (type.equals("text/plain")) {
                handleSendText(intent);
            } else {
                statusTextView.setText("Unsupported content type received: " + type);
            }
        } else if (Intent.ACTION_SEND_MULTIPLE.equals(action) && type != null) {
            if (type.startsWith("image/")) {
                handleSendMultipleImages(intent);
            } else {
                statusTextView.setText("Unsupported multiple content type received: " + type);
            }
        } else {
            statusTextView.setText("No content shared or unsupported action.");
        }
    }

    private void handleSendText(Intent intent) {
        String sharedText = intent.getStringExtra(Intent.EXTRA_TEXT);
        if (sharedText != null) {
            statusTextView.setText("Shared Text:");
            sharedTextView.setText(sharedText);
            sharedTextView.setVisibility(TextView.VISIBLE);
        } else {
            statusTextView.setText("No text found in the shared intent.");
        }
    }

    private void handleSendImage(Intent intent) {
        Uri imageUri = intent.getParcelableExtra(Intent.EXTRA_STREAM);
        if (imageUri != null) {
            statusTextView.setText("Shared Image:");
            sharedImageView.setImageURI(imageUri);
            sharedImageView.setVisibility(ImageView.VISIBLE);
            // Grant read permission to our app for the URI
            // This is crucial for accessing content from other apps
            intent.addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION);
        } else {
            statusTextView.setText("No image URI found in the shared intent.");
        }
    }

    private void handleSendMultipleImages(Intent intent) {
        ArrayList<Uri> imageUris = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM);
        if (imageUris != null && !imageUris.isEmpty()) {
            statusTextView.setText("Shared Multiple Images (showing first):");
            sharedImageView.setImageURI(imageUris.get(0)); // Display the first image
            sharedImageView.setVisibility(ImageView.VISIBLE);
            // Grant read permission for all URIs (though we only display the first)
            for (Uri uri : imageUris) {
                // Not strictly necessary to add flag for each URI if only the first is displayed,
                // but good practice if processing all.
                intent.addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION);
            }
        } else {
            statusTextView.setText("No image URIs found in the shared intent.");
        }
    }
}

